import React, {useState, useRef} from 'react'
import styled from 'styled-components'
import {shopSelector} from '../redux/shopSlice.js'
import {useSelector} from 'react-redux'

const FilterSectionWrapper = styled.div `
display:flex;
justify-content:center;
align-items:center;
`

const FilterItem = styled.div `
width:100px;
height:30px;
border-radius:6px;
border:1.2px solid #1C1C1C;
margin:10px;
text-align:center;
line-height:30px;
`

export default function ListingCard () {
	const filterListSelector = useSelector(shopSelector)


	return (
		<FilterSectionWrapper>
			{filterListSelector.filter.map(filterItem => <FilterItem>{filterItem}</FilterItem>)}
		</FilterSectionWrapper>
	)
}
